// Format ALL CRM contacts for Lusha Bulk Enrichment API
// Builds the full payload: { contacts: [...], metadata: {} }
const items = $input.all();
let contactIdCounter = 1;

const contacts = items
  .filter(item => item.json.properties?.email)
  .map(item => ({
    contactId: String(contactIdCounter++),
    email: item.json.properties.email
  }));

const payload = {
  contacts,
  metadata: {}
};

return [{ json: { contactsPayload: JSON.stringify(payload) } }];

// ICP Qualification Logic — process each bulk-enriched contact
// Match enriched results back to original CRM records by email
const items = $input.all();
const crmContacts = $('Get Contacts Needing Refresh').all();

// Build email → CRM record lookup
const crmByEmail = {};
for (const c of crmContacts) {
  const email = (c.json.properties?.email || '').toLowerCase();
  if (email) crmByEmail[email] = c.json;
}

const ICP = {
  targetSeniority: ['vp', 'director', 'c-suite', 'founder', 'head'],
  minCompanySize: 50,
  targetIndustries: ['technology', 'software', 'saas', 'fintech'],
};

const results = [];
for (const item of items) {
  const lusha = item.json;
  const email = (lusha.primaryEmail || '').toLowerCase();
  const crm = crmByEmail[email] || {};

  let qualScore = 0;
  const signals = [];

  // Seniority scoring
  const seniority = (lusha.seniority || '').toLowerCase();
  if (ICP.targetSeniority.some(s => seniority.includes(s))) {
    qualScore += 30; signals.push('ICP seniority match');
  }

  // Company size scoring
  const empMax = Array.isArray(lusha.companySize) ? lusha.companySize[1] : 0;
  if (empMax >= ICP.minCompanySize) {
    qualScore += 25; signals.push(`Company size: ${empMax}`);
  }

  // Industry scoring
  const industry = (lusha.companyMainIndustry || '').toLowerCase();
  if (ICP.targetIndustries.some(i => industry.includes(i))) {
    qualScore += 20; signals.push('Target industry match');
  }

  if (lusha.primaryPhone) { qualScore += 10; signals.push('Has phone'); }
  if (lusha.primaryEmail) { qualScore += 10; signals.push('Has verified email'); }

  let workflow = 'nurture';
  if (qualScore >= 70) workflow = 'fast-track';
  else if (qualScore >= 40) workflow = 'standard-outreach';

  results.push({
    json: {
      contactId: crm.id || '',
      email: crm.properties?.email || lusha.primaryEmail,
      firstName: lusha.firstName || crm.properties?.firstname,
      lastName: lusha.lastName || crm.properties?.lastname,
      jobTitle: lusha.jobTitle,
      seniority: lusha.seniority,
      phone: lusha.primaryPhone,
      company: lusha.companyName,
      companySize: empMax,
      industry: lusha.companyMainIndustry,
      qualificationScore: qualScore,
      signals,
      targetWorkflow: workflow,
      syncedAt: new Date().toISOString()
    }
  });
}

return results;
